def access_token_added(self, userobj, name):
    if not self.send_changed:
        return

    if not userobj.email:
        logger.info("can't sent mail to user [%s] without an email", userobj.username)
        return

    # Send a mail notification
    body = self.app.templates.compile_template(
        "access_token_added.html", **{"header_name": self.app.cfg.header_name, 'user': userobj, 'name': name}
    )
    self.bus.publish('queue_mail', to=userobj.email, subject=_("A new access token has been created"), message=body)

def user_password_changed(self, userobj):
    if not self.send_changed:
        return

    if not userobj.email:
        logger.info("can't sent mail to user [%s] without an email", userobj.username)
        return

    # If the email attributes was changed, send a mail notification.
    body = self.app.templates.compile_template(
        "password_changed.html", **{"header_name": self.app.cfg.header_name, 'user': userobj}
    )
    self.bus.publish('queue_mail', to=userobj.email, subject=_("Password changed"), message=body)

def index():
    """ Index handler """

    send = request.vars.send
    if DEMO_MODE:
        session.authorized = True
        session.last_time = t0
    if not send:
        send = URL('site')
    if session.authorized:
        redirect(send)
    elif failed_login_count() >= allowed_number_of_attempts:
        time.sleep(2 ** allowed_number_of_attempts)
        raise HTTP(403)
    elif request.vars.password:
        if verify_password(request.vars.password[:1024]):
            session.authorized = True
            login_record(True)

            if CHECK_VERSION:
                session.check_version = True
            else:
                session.check_version = False

            session.last_time = t0
            if isinstance(send, list):  # ## why does this happen?
                send = str(send[0])

            redirect(send)
        else:
            times_denied = login_record(False)
            if times_denied >= allowed_number_of_attempts:
                response.flash = \
                    T('admin disabled because too many invalid login attempts')
            elif times_denied == allowed_number_of_attempts - 1:
                response.flash = \
                    T('You have one more login attempt before you are locked out')
            else:
                response.flash = T('invalid password.')
    return dict(send=send)

def reset_password(request):
    '''
    Password reset handling.
    '''
    if 'email' not in load_backends(BACKENDS).keys():
        messages.error(
            request,
            _('Can not reset password, email authentication is disabled!')
        )
        return redirect('login')

    if request.method == 'POST':
        form = ResetForm(request.POST)
        if form.is_valid():
            # Force creating new session
            request.session.create()
            if request.user.is_authenticated():
                logout(request)

            request.session['password_reset'] = True
            return complete(request, 'email')
    else:
        form = ResetForm()

    return render(
        request,
        'accounts/reset.html',
        {
            'title': _('Password reset'),
            'form': form,
        }
    )

def visit_Call(self, node):
    """ A couple function calls are supported: bson's ObjectId() and
    datetime().
    """
    if isinstance(node.func, ast.Name):
        expr = None
        if node.func.id == 'ObjectId':
            expr = "('" + node.args[0].s + "')"
        elif node.func.id == 'datetime':
            values = []
            for arg in node.args:
                values.append(str(arg.n))
            expr = "(" + ", ".join(values) + ")"
        if expr:
            self.current_value = eval(node.func.id + expr)

async def file(path_or_url: str, request: fastapi.Request):
    blocks = app.get_blocks()
    if utils.validate_url(path_or_url):
        return RedirectResponse(
            url=path_or_url, status_code=status.HTTP_302_FOUND
        )
    abs_path = utils.abspath(path_or_url)

    in_blocklist = any(
        utils.is_in_or_equal(abs_path, blocked_path)
        for blocked_path in blocks.blocked_paths
    )
    is_dir = abs_path.is_dir()

    if in_blocklist or is_dir:
        raise HTTPException(403, f"File not allowed: {path_or_url}.")

    created_by_app = str(abs_path) in set().union(*blocks.temp_file_sets)
    in_allowlist = any(
        utils.is_in_or_equal(abs_path, allowed_path)
        for allowed_path in blocks.allowed_paths
    )
    was_uploaded = utils.is_in_or_equal(abs_path, app.uploaded_file_dir)
    is_cached_example = utils.is_in_or_equal(
        abs_path, utils.abspath(CACHED_FOLDER)
    )

    if not (
        created_by_app or in_allowlist or was_uploaded or is_cached_example
    ):
        raise HTTPException(403, f"File not allowed: {path_or_url}.")

    if not abs_path.exists():
        raise HTTPException(404, f"File not found: {path_or_url}.")

    range_val = request.headers.get("Range", "").strip()
    if range_val.startswith("bytes=") and "-" in range_val:
        range_val = range_val[6:]
        start, end = range_val.split("-")
        if start.isnumeric() and end.isnumeric():
            start = int(start)
            end = int(end)
            response = ranged_response.RangedFileResponse(
                abs_path,
                ranged_response.OpenRange(start, end),
                dict(request.headers),
                stat_result=os.stat(abs_path),
            )
            return response

    return FileResponse(abs_path, headers={"Accept-Ranges": "bytes"})

def _check_signature(self, decoded_xml, item, node_name=NODE_NAME, origdoc=None, id_attr='', must=False, only_valid_cert=False, issuer=None):
    try:
        _issuer = item.issuer.text.strip()
    except AttributeError:
        _issuer = None

    if _issuer is None:
        try:
            _issuer = issuer.text.strip()
        except AttributeError:
            _issuer = None

    # More trust in certs from metadata then certs in the XML document
    if self.metadata:
        try:
            _certs = self.metadata.certs(_issuer, 'any', 'signing')
        except KeyError:
            _certs = []
        certs = []

        for cert in _certs:
            if isinstance(cert, six.string_types):
                content = pem_format(cert)
                tmp = make_temp(content,
                                suffix=".pem",
                                decode=False,
                                delete_tmpfiles=self.delete_tmpfiles)
                certs.append(tmp)
            else:
                certs.append(cert)
    else:
        certs = []

    if not certs and not self.only_use_keys_in_metadata:
        logger.debug('==== Certs from instance ====')
        certs = [
            make_temp(content=pem_format(cert),
                      suffix=".pem",
                      decode=False,
                      delete_tmpfiles=self.delete_tmpfiles)
            for cert in cert_from_instance(item)
        ]
    else:
        logger.debug('==== Certs from metadata ==== %s: %s ====', _issuer, certs)

    if not certs:
        raise MissingKey(_issuer)

    verified = False
    last_pem_file = None

    for pem_fd in certs:
        try:
            last_pem_file = pem_fd.name
            if self.verify_signature(
                    decoded_xml,
                    pem_fd.name,
                    node_name=node_name,
                    node_id=item.id,
                    id_attr=id_attr):
                verified = True
                break
        except XmlsecError as exc:
            logger.error('check_sig: %s', exc)
            pass
        except Exception as exc:
            logger.error('check_sig: %s', exc)
            raise

    if verified or only_valid_cert:
        if not self.cert_handler.verify_cert(last_pem_file):
            raise CertificateError('Invalid certificate!')
    else:
        raise SignatureError('Failed to verify signature')

    return item

